mapper.select:
SELECT COUNT(*)
FROM sys_car_plate
WHERE community_id = #{communityId}
  AND house_no = #{houseNo}
  AND status IN ('normal', 'primary')
  AND is_deleted = 0

mapper.update:
UPDATE sys_car_plate
SET status = 'disabled', update_time = NOW()
WHERE community_id = #{communityId}
  AND house_no = #{houseNo}
  AND is_deleted = 0

mapper.select:
SELECT COUNT(*)
FROM sys_car_plate
WHERE community_id = #{communityId}
  AND house_no = #{houseNo}
  AND owner_id = #{ownerId}
  AND is_deleted = 0

SELECT COUNT(*)
FROM sys_car_plate
WHERE community_id = #{communityId}
  AND car_number = #{carNumber}
  AND owner_id != #{ownerId}
  AND is_deleted = 0
